SELECT

FROM ai_business_quantity_ledger
WHERE tenant_id = #{tenantId}
  AND idempotency_key = #{idempotencyKey}
ORDER BY create_time DESC, id DESC
LIMIT 1

SELECT id, operation_type AS operationType, account_code AS accountCode, item_code AS itemCode, dimension_key AS dimensionKey, quantity_delta AS quantityDelta, balance_quantity AS balanceQuantity, locked_quantity AS lockedQuantity, target_account_code AS targetAccountCode, target_item_code AS targetItemCode, target_dimension_key AS targetDimensionKey, source_object_code AS sourceObjectCode, source_record_id AS sourceRecordId, source_detail_id AS sourceDetailId, lock_id AS lockId, correlation_id AS correlationId, remark, extra_data AS extraData, create_time AS createTime FROM ai_business_quantity_ledger WHERE tenant_id = #{tenantId}
AND operation_type = #{query.operationType}
AND account_code = #{query.accountCode}
AND item_code = #{query.itemCode}
AND dimension_key = #{query.dimensionKey}
AND source_object_code = #{query.sourceObjectCode}
AND source_record_id = #{query.sourceRecordId}
AND source_detail_id = #{query.sourceDetailId}
ORDER BY create_time DESC, id DESC
